async (params, browser) => {
  // Search Facebook
  await browser.open(`https://www.facebook.com/search/top/?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('[role=\'feed\'], [role=\'main\']', 15000)

  // Let results render
  await browser.wait(3000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const feedItems = document.querySelectorAll('[role="feed"] > div, [role="main"] [data-ad-preview], [role="article"]'); for (let i = 0; i < Math.min(feedItems.length, 15); i++) { const el = feedItems[i]; const linkEls = el.querySelectorAll('a[href]'); let profileLink = ''; let profileName = ''; let snippet = ''; let resultType = 'post'; for (const link of linkEls) { const href = link.getAttribute('href') || ''; if (href.includes('facebook.com/') && !href.includes('/search/') && !href.includes('#') && !href.includes('policies') && !href.includes('help.')) { if (!profileLink) { profileLink = href; profileName = link.textContent.trim(); } if (href.includes('/posts/') || href.includes('/photos/') || href.includes('/videos/')) { resultType = 'post'; } else if (href.includes('/groups/')) { resultType = 'group'; } else if (href.includes('/events/')) { resultType = 'event'; } else if (!href.includes('/posts/')) { resultType = 'page_or_profile'; } break; } } const textEls = el.querySelectorAll('div[dir="auto"], span[dir="auto"]'); for (const t of textEls) { const text = t.textContent.trim(); if (text.length > 20 && text.length < 1000) { snippet = text.substring(0, 300); break; } } if (profileName || snippet) { results.push({ name: profileName || '', snippet: snippet, type: resultType, url: profileLink }); } } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
